from dataclasses import dataclass, field
from datetime import datetime, timezone

@dataclass
class GDPR33Notification:
    controller_name: str
    dpo_contact: str
    breach_discovery: datetime
    breach_nature: str          # e.g. "Confidentiality breach — unauthorised AI output"
    categories_of_subjects: list[str]
    approximate_subject_count: int
    categories_of_data: list[str]
    approximate_record_count: int
    likely_consequences: str
    measures_taken: str
    measures_proposed: str

    def notification_deadline(self) -> datetime:
        return self.breach_discovery + __import__('datetime').timedelta(hours=72)

    def is_within_window(self) -> bool:
        return datetime.now(timezone.utc) <= self.notification_deadline()

    def render_summary(self) -> str:
        deadline = self.notification_deadline()
        status = "ON TIME" if self.is_within_window() else "OVERDUE"
        return f"""
GDPR Art. 33 — Breach Notification to Supervisory Authority [{status}]
Controller: {self.controller_name}
DPO: {self.dpo_contact}
Discovery: {self.breach_discovery.isoformat()}
Notification deadline: {deadline.isoformat()}

Nature: {self.breach_nature}
Data subjects: ~{self.approximate_subject_count} ({', '.join(self.categories_of_subjects)})
Records affected: ~{self.approximate_record_count} ({', '.join(self.categories_of_data)})

Consequences: {self.likely_consequences}
Actions taken: {self.measures_taken}
Actions planned: {self.measures_proposed}
""".strip()
